class HTTPClient {
    static let shared = HTTPClient()
    
    private let session: URLSession
    
    private init() {
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        
        let delegate = SessionDelegate()
        session = URLSession(configuration: configuration, delegate: delegate, delegateQueue: nil)
    }
    
    func request(
        url: String,
        method: String = "GET",
        headers: [String: String]? = nil,
        body: Data? = nil,
        completion: @escaping (Result<(Data, HTTPURLResponse), Error>) -> Void
    ) {
        guard let requestURL = URL(string: url) else {
            completion(.failure(HTTPError.invalidURL))
            return
        }
        
        var request = URLRequest(url: requestURL)
        request.httpMethod = method
        request.httpBody = body
        
        if let headers = headers {
            for (key, value) in headers {
                request.setValue(value, forHTTPHeaderField: key)
            }
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(HTTPError.invalidResponse))
                return
            }
            
            guard let data = data else {
                completion(.failure(HTTPError.noData))
                return
            }
            
            completion(.success((data, httpResponse)))
        }
        
        task.resume()
    }
    
    func get(url: String, headers: [String: String]? = nil, completion: @escaping (Result<(Data, HTTPURLResponse), Error>) -> Void) {
        request(url: url, method: "GET", headers: headers, completion: completion)
    }
    
    func post(url: String, headers: [String: String]? = nil, body: Data? = nil, completion: @escaping (Result<(Data, HTTPURLResponse), Error>) -> Void) {
        request(url: url, method: "POST", headers: headers, body: body, completion: completion)
    }
    
