class SessionDelegate: NSObject, URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust {
            let host = challenge.protectionSpace.host
            
            if host.hasPrefix("192.168.") || host.hasPrefix("10.") || host.hasPrefix("172.") || host == "localhost" {
                if let serverTrust = challenge.protectionSpace.serverTrust {
                    let credential = URLCredential(trust: serverTrust)
                    completionHandler(.useCredential, credential)
                } else {
                    completionHandler(.performDefaultHandling, nil)
                }
            } else {
                completionHandler(.performDefaultHandling, nil)
            }
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

enum HTTPError: Error {
    case invalidURL
    case invalidResponse
    case noData
    case serverError(Int)
}

class IoTDevice {
    let ipAddress: String
    let name: String
    
    init(ipAddress: String, name: String) {
        self.ipAddress = ipAddress
        self.name = name
    }
    
    var baseURL: String {
        return "http://\(ipAddress)"
    }
    
    func getStatus(completion: @escaping (Result<[String: Any], Error>) -> Void) {
        let url = "\(baseURL)/status"
        
        HTTPClient.shared.get(url: url) { result in
            switch result {
            case .success((let data, _)):
                do {
                    if let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] {
                        completion(.success(json))
                    } else {
                        completion(.failure(HTTPError.invalidResponse))
                    }
                } catch {
                    completion(.failure(error))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func sendCommand(_ command: String, parameters: [String: Any]? = nil, completion: @escaping (Result<[String: Any], Error>) -> Void) {
        let url = "\(baseURL)/command"
        
        var payload: [String: Any] = ["command": command]
        if let parameters = parameters {
            payload["parameters"] = parameters
        }
        
        guard let body = try? JSONSerialization.data(withJSONObject: payload) else {
            completion(.failure(HTTPError.invalidURL))
            return
        }
        
        let headers = ["Content-Type": "application/json"]
        
        HTTPClient.shared.post(url: url, headers: headers, body: body) { result in
            switch result {
            case .success((let data, _)):
                do {
                    if let json = try JSONSerialization.jsonObject(with: data) as? [String: Any] {
                        completion(.success(json))
                    } else {
                        completion(.failure(HTTPError.invalidResponse))
                    }
                } catch {
                    completion(.failure(error))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
}

