class DeviceManager {
    static let shared = DeviceManager()
    
    private var localDevices: [IoTDevice] = []
    
    func addLocalDevice(ipAddress: String, name: String) {
        let device = IoTDevice(ipAddress: ipAddress, name: name)
        localDevices.append(device)
    }
    
    func getLocalDevices() -> [IoTDevice] {
        return localDevices
    }
    
    func discoverDevices(in subnet: String = "192.168.1", completion: @escaping ([IoTDevice]) -> Void) {
        var discoveredDevices: [IoTDevice] = []
        let dispatchGroup = DispatchGroup()
        
        for i in 1...254 {
            let ip = "\(subnet).\(i)"
            dispatchGroup.enter()
            
            let device = IoTDevice(ipAddress: ip, name: "Device \(ip)")
            device.getStatus { result in
                switch result {
                case .success:
                    discoveredDevices.append(device)
                case .failure:
                    break
                }
                dispatchGroup.leave()
            }
        }
        
        dispatchGroup.notify(queue: .main) {
            self.localDevices = discoveredDevices
            completion(discoveredDevices)
        }
    }
}

